					hum:ChangeState(Enum.HumanoidStateType.Jumping);
					hum.Jump = true;
					jumpCD = tick();
				end
			end
			if ((speed < 1) and (hDist > 1) and ((tick() - jumpCD) > 0.6)) then
				if ((wp.Position.Y >= (root.Position.Y - 4)) and Movement.hasObstacleAhead(wp.Position) and Movement.isGrounded()) then
					hum:ChangeState(Enum.HumanoidStateType.Jumping);
					hum.Jump = true;
					jumpCD = tick();
				end
				hum:MoveTo(wp.Position);
			end
			if ((tick() - stuckTimer) > 0.8) then
				local sdx, sdz = livePos.X - stuckPos.X, livePos.Z - stuckPos.Z;
				if (math.sqrt((sdx * sdx) + (sdz * sdz)) < 0.5) then
					if Movement.isGrounded() then
						hum:ChangeState(Enum.HumanoidStateType.Jumping);
						hum.Jump = true;
						jumpCD = tick();
					end
					hum:MoveTo(wp.Position);
				end
				stuckPos = livePos;
				stuckTimer = tick();
			end
			task.wait(0.02);
		end
