local function mainLoop()
	while true do
		while State.IsResetting do
			task.wait(0.1);
		end
		if CONFIG.Enabled then
			local target = EggManager.getBestTarget();
			if target then
				Movement.collectTarget(target);
				if pathFolder then
					pathFolder:ClearAllChildren();
				end
				task.wait(0.2);
			else
				if (State.Status ~= LUAOBFUSACTOR_DECRYPT_STR_0("\64\53\37\4", "\153\23\116\108\80\191\69\219")) then
